package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidPathAndCharset() throws Exception {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Use reflection to mock Files.newBufferedWriter
        var filesClass = Files.class;
        var newBufferedWriterMethod = filesClass.getMethod("newBufferedWriter", Path.class, java.nio.charset.Charset.class);

        // Create a spy of csvFormat to override print(Appendable)
        CSVFormat spyFormat = spy(csvFormat);

        // When print(Appendable) is called, return mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

        // Use a manual mocking approach for Files.newBufferedWriter by using a custom class loader or a helper method
        // Since mockStatic is not available, we simulate by overriding the method via reflection in the test (not trivial)
        // Instead, we create a subclass of CSVFormat with overridden print(Path, Charset) method for testing

        CSVFormat testFormat = new CSVFormat(spyFormat.getDelimiter(),
                spyFormat.getQuoteCharacter(),
                spyFormat.getQuoteMode(),
                spyFormat.getCommentMarker(),
                spyFormat.getEscapeCharacter(),
                spyFormat.getIgnoreSurroundingSpaces(),
                spyFormat.getIgnoreEmptyLines(),
                spyFormat.getRecordSeparator(),
                spyFormat.getNullString(),
                null,
                spyFormat.getHeader(),
                spyFormat.getSkipHeaderRecord(),
                spyFormat.getAllowMissingColumnNames(),
                spyFormat.getIgnoreHeaderCase(),
                spyFormat.getTrim(),
                spyFormat.getTrailingDelimiter(),
                spyFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                // Instead of calling Files.newBufferedWriter, call print(Appendable) directly with StringWriter
                return print(new StringWriter());
            }
        };

        CSVFormat spyTestFormat = spy(testFormat);
        doReturn(mockPrinter).when(spyTestFormat).print(any(Appendable.class));

        CSVPrinter result = spyTestFormat.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(result);
        verify(spyTestFormat).print(any(Appendable.class));
    }

    @Test
    void testPrintThrowsIOExceptionWhenFilesNewBufferedWriterFails() throws IOException {
        Path mockPath = mock(Path.class);

        // Create a subclass to simulate IOException on print(Path, Charset)
        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                throw new IOException("File write error");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> testFormat.print(mockPath, StandardCharsets.UTF_8));
        assertEquals("File write error", thrown.getMessage());
    }
}
